    u_xlat11.x = (-u_xlat5.x) + u_xlat11.x;
    u_xlat5.x = u_xlat16_1.x + (-u_xlat5.x);
    u_xlat11.x = float(1.0) / u_xlat11.x;
    u_xlat5.x = u_xlat11.x * u_xlat5.x;
    u_xlat5.x = clamp(u_xlat5.x, 0.0, 1.0);
    u_xlat11.x = u_xlat5.x * -2.0 + 3.0;
    u_xlat5.x = u_xlat5.x * u_xlat5.x;
    u_xlat5.x = u_xlat5.x * u_xlat11.x;
    u_xlat16_1.x = (-_BandsSmoothing) * 0.5 + 0.5;
    u_xlat16_7 = _BandsSmoothing * 0.5 + 0.5;
