    u_xlat11.x = (-u_xlat16_1.x) + u_xlat11.x;
    u_xlat17 = float(1.0) / u_xlat17;
    u_xlat11.x = u_xlat17 * u_xlat11.x;
    u_xlat11.x = clamp(u_xlat11.x, 0.0, 1.0);
    u_xlat17 = u_xlat11.x * -2.0 + 3.0;
    u_xlat11.x = u_xlat11.x * u_xlat11.x;
    u_xlat5.x = floor(u_xlat5.x);
    u_xlat5.x = u_xlat17 * u_xlat11.x + u_xlat5.x;
    u_xlat5.x = u_xlat5.x / _BandsCount;
    u_xlat5.x = clamp(u_xlat5.x, 0.0, 1.0);
    u_xlat0.xyz = u_xlat16_0.xyz * _Color.xyz + (-_SColor.xyz);
    u_xlat0.xyz = u_xlat5.xxx * u_xlat0.xyz + _SColor.xyz;
